func (o *User) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "ManagerCompanies":
		rels, ok := retrieved.(CompanySlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.ManagerCompanies = rels
		o.R.Loaded.ManagerCompanies = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.ManagerUser = o
				rel.R.Loaded.ManagerUser = true
			}
		}
		return nil
	case "OwnerCompanies":
		rels, ok := retrieved.(CompanySlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.OwnerCompanies = rels
		o.R.Loaded.OwnerCompanies = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.OwnerUser = o
				rel.R.Loaded.OwnerUser = true
			}
		}
		return nil
	case "UserType":
		rel, ok := retrieved.(*UserType)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.UserType = rel
		o.R.Loaded.UserType = true

		if rel != nil {
			rel.R.Users = UserSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("user has no relationship %q", name)
	}
}

