// LoadManagerCompanies loads the user's ManagerCompanies into the .R struct
func (o *User) LoadManagerCompanies(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.ManagerCompanies = nil
	o.R.Loaded.ManagerCompanies = false

	related, err := o.ManagerCompanies(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.ManagerUser = o
		rel.R.Loaded.ManagerUser = true
	}

	o.R.ManagerCompanies = related
	o.R.Loaded.ManagerCompanies = true
	return nil
}

// LoadManagerCompanies loads the user's ManagerCompanies into the .R struct
func (os UserSlice) LoadManagerCompanies(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	companies, err := os.ManagerCompanies(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.ManagerCompanies = nil
		o.R.Loaded.ManagerCompanies = true
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range companies {

			if !rel.ManagerID.IsValue() {
				continue
			}
			if !(rel.ManagerID.IsValue() && o.ID == rel.ManagerID.MustGet()) {
				continue
			}

			rel.R.ManagerUser = o
			rel.R.Loaded.ManagerUser = true

			o.R.ManagerCompanies = append(o.R.ManagerCompanies, rel)
		}
	}

	return nil
}

