type userCountPreloader struct {
	ManagerCompanies func(...bob.Mod[*dialect.SelectQuery]) psql.Preloader
	OwnerCompanies   func(...bob.Mod[*dialect.SelectQuery]) psql.Preloader
}

func buildUserCountPreloader() userCountPreloader {
	return userCountPreloader{
		ManagerCompanies: func(mods ...bob.Mod[*dialect.SelectQuery]) psql.Preloader {
			return countPreloader[*User]("ManagerCompanies", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = Users.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(psql.Raw("count(*)")),

					sm.From(Companies.Name()),
					sm.Where(psql.Quote(Companies.Alias(), "manager_id").EQ(psql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return psql.Group(psql.Select(subqueryMods...).Expression)
			})
		},
		OwnerCompanies: func(mods ...bob.Mod[*dialect.SelectQuery]) psql.Preloader {
			return countPreloader[*User]("OwnerCompanies", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = Users.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(psql.Raw("count(*)")),

					sm.From(Companies.Name()),
					sm.Where(psql.Quote(Companies.Alias(), "owner_id").EQ(psql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return psql.Group(psql.Select(subqueryMods...).Expression)
			})
		},
	}
}

type userCountThenLoader[Q orm.Loadable] struct {
	ManagerCompanies func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	OwnerCompanies   func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildUserCountThenLoader[Q orm.Loadable]() userCountThenLoader[Q] {
	type ManagerCompaniesCountInterface interface {
		LoadCountManagerCompanies(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type OwnerCompaniesCountInterface interface {
		LoadCountOwnerCompanies(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return userCountThenLoader[Q]{
		ManagerCompanies: countThenLoadBuilder[Q](
			"ManagerCompanies",
			func(ctx context.Context, exec bob.Executor, retrieved ManagerCompaniesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountManagerCompanies(ctx, exec, mods...)
			},
		),
		OwnerCompanies: countThenLoadBuilder[Q](
			"OwnerCompanies",
			func(ctx context.Context, exec bob.Executor, retrieved OwnerCompaniesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountOwnerCompanies(ctx, exec, mods...)
			},
		),
	}
}

// LoadCountManagerCompanies loads the count of ManagerCompanies into the C struct
func (o *User) LoadCountManagerCompanies(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	count, err := o.ManagerCompanies(mods...).Count(ctx, exec)
	if err != nil {
		return err
	}

	o.C.ManagerCompanies = &count
	return nil
}

// LoadCountManagerCompanies loads the count of ManagerCompanies for a slice in a single batch query
func (os UserSlice) LoadCountManagerCompanies(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	// Build the IN arg expression from parent PKs

	pkID := make(pgtypes.Array[string], 0, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}
		pkID = append(pkID, o.ID)
	}
	PKArgExpr := psql.Select(sm.Columns(
		psql.F("unnest", psql.Cast(psql.Arg(pkID), "uuid[]")),
	))

	// countResult holds one scanned row from the batch count query.
	// FK columns are aliased to the parent PK column names for direct map lookup.
	type countResult struct {
		ID    string
		Count int64
	}

	batchMods := []bob.Mod[*dialect.SelectQuery]{
		// SELECT fk AS parent_pk, count(*)
		sm.Columns(
			Companies.Columns.ManagerID.As("id"),
			psql.Raw("count(*) as count"),
		),
		// Single-hop: FROM related table directly
		sm.From(Companies.NameAs()),

		// WHERE fk IN (parent PKs)
		sm.Where(Companies.Columns.ManagerID.OP("IN", PKArgExpr)),
		// GROUP BY fk columns
		sm.GroupBy(Companies.Columns.ManagerID),
	}
	batchMods = append(batchMods, mods...)

	results, err := bob.All(ctx, exec,
		psql.Select(batchMods...),
		scan.StructMapper[countResult](),
	)
	if err != nil {
		return err
	}

	// Single-column FK: direct map lookup
	countMap := make(map[string]int64, len(results))
	for _, r := range results {
		countMap[r.ID] = r.Count
	}
	for _, o := range os {
		if o == nil {
			continue
		}
		count := countMap[o.ID]
		o.C.ManagerCompanies = &count
	}

	return nil
}

