type userJoins[Q dialect.Joinable] struct {
	typ              string
	ManagerCompanies modAs[Q, companyColumns]
	OwnerCompanies   modAs[Q, companyColumns]
	UserType         modAs[Q, userTypeColumns]
}

func (j userJoins[Q]) aliasedAs(alias string) userJoins[Q] {
	return buildUserJoins[Q](buildUserColumns(alias), j.typ)
}

func buildUserJoins[Q dialect.Joinable](cols userColumns, typ string) userJoins[Q] {
	return userJoins[Q]{
		typ: typ,
		ManagerCompanies: modAs[Q, companyColumns]{
			c: Companies.Columns,
			f: func(to companyColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Companies.Name().As(to.Alias())).On(
						to.ManagerID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		OwnerCompanies: modAs[Q, companyColumns]{
			c: Companies.Columns,
			f: func(to companyColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Companies.Name().As(to.Alias())).On(
						to.OwnerID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		UserType: modAs[Q, userTypeColumns]{
			c: UserTypes.Columns,
			f: func(to userTypeColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, UserTypes.Name().As(to.Alias())).On(
						to.Code.EQ(cols.UserType),
					))
				}

				return mods
			},
		},
	}
}
